__global__ void
kmeans_swap(float  *feature,   
			float  *feature_swap,
			int     npoints,
			int     nfeatures
){

	unsigned int tid = threadIdx.x + blockIdx.x * blockDim.x;



    if (tid < npoints){
	    for(int i = 0; i <  nfeatures; i++)
		    feature_swap[i * npoints + tid] = feature[tid * nfeatures + i];
    }

}

